window.VIRAL_QUESTIONS.push(...[{"id":"Q051","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 162","question":{"en":"What is the causative virus family of molluscum contagiosum?","ar":"إلى أي عائلة ينتمي الفيروس المسبب للمليساء المعدية؟"},"options":[{"letter":"A","en":"Poxviridae","ar":"عائلة فيروسات الجدري"},{"letter":"B","en":"Herpesviridae","ar":"عائلة الهربس"},{"letter":"C","en":"Orthomyxoviridae","ar":"الأورثوميكسو"},{"letter":"D","en":"Retroviridae","ar":"الفيروسات القهقرية"}],"correct":"A","explanation":{"en":"Molluscum contagiosum virus is a poxvirus.","ar":"فيروس المليساء المعدية من فيروسات الجدري."},"reasoning":{"en":"The poxviral proliferative lesion explains the characteristic papular morphology rather than a vesicular exanthem.","ar":"تفسر الآفة التكاثرية لفيروس الجدري الشكل الحطاطي المميز بدلًا من طفح حويصلي."},"image":null},{"id":"Q052","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 163","question":{"en":"Which approach is reasonable for uncomplicated molluscum in an immunocompetent child?","ar":"أي نهج مناسب للمليساء غير المعقدة لدى طفل سليم المناعة؟"},"options":[{"letter":"A","en":"Observation and reassurance","ar":"الملاحظة والطمأنة"},{"letter":"B","en":"Routine IV acyclovir","ar":"أسيكلوفير وريدي روتيني"},{"letter":"C","en":"Long-term systemic steroids","ar":"كورتيزون جهازي طويل المدى"},{"letter":"D","en":"Emergency surgical debridement","ar":"تنضير جراحي عاجل"}],"correct":"A","explanation":{"en":"Molluscum is usually self-limited, so observation is acceptable when lesions are not troublesome.","ar":"المليساء غالبًا محدودة ذاتيًا، لذا تكون الملاحظة مقبولة عندما لا تسبب الآفات مشكلة."},"reasoning":{"en":"Treatment is individualized for symptoms, spread, eczema, cosmetic concerns, genital location, or immunosuppression.","ar":"يُفصل العلاج حسب الأعراض والانتشار والإكزيما والناحية التجميلية والمكان التناسلي أو تثبيط المناعة."},"image":null},{"id":"Q053","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 164","question":{"en":"Numerous giant, treatment-resistant molluscum lesions should prompt evaluation for what?","ar":"وجود آفات مليساء عديدة وضخمة ومقاومة للعلاج يستدعي تقييم ماذا؟"},"options":[{"letter":"A","en":"Immunodeficiency such as HIV","ar":"نقص المناعة مثل HIV"},{"letter":"B","en":"Isolated iron deficiency only","ar":"نقص الحديد المنفرد فقط"},{"letter":"C","en":"Simple dehydration","ar":"جفاف بسيط"},{"letter":"D","en":"Hyperthyroidism only","ar":"فرط نشاط الدرق فقط"}],"correct":"A","explanation":{"en":"Extensive, giant, facial, or refractory lesions are more common in significant immunosuppression.","ar":"تشيع الآفات المنتشرة أو الضخمة أو الوجهية أو المقاومة مع تثبيط مناعي مهم."},"reasoning":{"en":"The lesion burden may be a dermatologic clue to an underlying immune disorder.","ar":"قد يكون عبء الآفات علامة جلدية على اضطراب مناعي كامن."},"image":null},{"id":"Q054","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"MCQ","difficulty":"Hard","source":"PDF p. 166","question":{"en":"Which COVID-19 skin manifestation resembles chilblains and often affects toes?","ar":"أي مظهر جلدي لكوفيد-19 يشبه لسعة البرد ويصيب أصابع القدم غالبًا؟"},"options":[{"letter":"A","en":"Pernio-like lesions (“COVID toes”)","ar":"آفات شبيهة بالشرث «أصابع كوفيد»"},{"letter":"B","en":"Koplik spots","ar":"بقع كوبليك"},{"letter":"C","en":"Condyloma acuminata","ar":"الثآليل التناسلية"},{"letter":"D","en":"Herpetic whitlow","ar":"الداحس الهربسي"}],"correct":"A","explanation":{"en":"Pernio-like acral lesions are popularly called COVID toes.","ar":"تسمى الآفات الطرفية الشبيهة بالشرث شائعًا أصابع كوفيد."},"reasoning":{"en":"Acral morphology and vascular-inflammatory context help distinguish them from classic viral vesicles.","ar":"يساعد الشكل الطرفي والسياق الوعائي الالتهابي على تمييزها عن الحويصلات الفيروسية التقليدية."},"image":null},{"id":"Q055","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"MCQ","difficulty":"Hard","source":"PDF p. 167","question":{"en":"Which COVID-associated skin pattern may signal severe vascular or thrombotic disease?","ar":"أي نمط جلدي مرتبط بكوفيد قد يشير إلى مرض وعائي أو تخثري شديد؟"},"options":[{"letter":"A","en":"Livedo reticularis or retiform purpura","ar":"الشبكية الزرقاء أو الفرفرية الشبكية"},{"letter":"B","en":"A single common wart","ar":"ثؤلول شائع واحد"},{"letter":"C","en":"Mild molluscum papule","ar":"حطاطة مليساء بسيطة"},{"letter":"D","en":"Stable flat nevus","ar":"وحمة مسطحة ثابتة"}],"correct":"A","explanation":{"en":"Livedoid or retiform purpuric lesions can reflect vascular occlusion and are more concerning than benign exanthems.","ar":"قد تعكس الآفات الشبكية أو الفرفرية انسدادًا وعائيًا وتكون أكثر إثارة للقلق من الطفوح الحميدة."},"reasoning":{"en":"Skin morphology can provide a clue to systemic severity and the need for urgent evaluation.","ar":"قد يوفر شكل الجلد دليلًا على شدة المرض الجهازي والحاجة إلى تقييم عاجل."},"image":null},{"id":"Q056","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Case","difficulty":"Easy","source":"PDF p. 106","question":{"en":"A 3-year-old has fever, painful cervical nodes, bleeding gums, and multiple painful oral vesicles and ulcers. What is the most likely diagnosis?","ar":"طفل عمره 3 سنوات لديه حمى وعقد عنقية مؤلمة ولثة نازفة وحويصلات وقرح فموية مؤلمة متعددة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Primary herpetic gingivostomatitis","ar":"التهاب اللثة والفم الهربسي الأولي"},{"letter":"B","en":"Recurrent herpes labialis","ar":"الهربس الشفوي المتكرر"},{"letter":"C","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"D","en":"Plantar warts","ar":"ثآليل أخمصية"}],"correct":"A","explanation":{"en":"Diffuse painful oral disease with gingivitis and systemic symptoms is typical of primary HSV-1 gingivostomatitis.","ar":"المرض الفموي المؤلم المنتشر مع التهاب اللثة والأعراض الجهازية نموذجي لعدوى HSV-1 الأولية."},"reasoning":{"en":"Age, fever, lymphadenopathy, gingival inflammation, and widespread lesions favor primary infection over a localized recurrence.","ar":"العمر والحمى وتضخم العقد والتهاب اللثة وانتشار الآفات ترجح العدوى الأولية على النوبة الموضعية المتكررة."},"image":null},{"id":"Q057","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Case","difficulty":"Easy","source":"PDF p. 107","question":{"en":"A dentist develops severe throbbing pain and grouped deep vesicles on one fingertip after treating a patient with oral ulcers. What is the diagnosis?","ar":"طبيب أسنان أصيب بألم نابض شديد وحويصلات عميقة متجمعة في طرف إصبع بعد علاج مريض بقرح فموية. ما التشخيص؟"},"options":[{"letter":"A","en":"Herpetic whitlow","ar":"الداحس الهربسي"},{"letter":"B","en":"Bacterial paronychia only","ar":"التهاب حول الظفر البكتيري فقط"},{"letter":"C","en":"Common wart","ar":"ثؤلول شائع"},{"letter":"D","en":"Erythema infectiosum","ar":"المرض الخامس"}],"correct":"A","explanation":{"en":"HSV can enter through small skin breaks and cause a painful vesicular infection of the finger.","ar":"قد يدخل HSV عبر شقوق جلدية صغيرة ويسبب عدوى حويصلية مؤلمة بالإصبع."},"reasoning":{"en":"The occupational exposure and grouped vesicles favor whitlow; routine incision may worsen viral spread and is not the primary treatment.","ar":"التعرض المهني والحويصلات المتجمعة يرجحان الداحس الهربسي، ولا يُعد الشق الروتيني علاجًا أوليًا وقد يزيد الانتشار."},"image":null},{"id":"Q058","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Case","difficulty":"Easy","source":"PDF p. 107","question":{"en":"A child with severe atopic dermatitis suddenly develops fever and hundreds of similar painful vesicles over eczematous areas. What is the most urgent diagnosis?","ar":"طفل لديه إكزيما تأتبية شديدة أصيب فجأة بحمى ومئات الحويصلات المؤلمة المتشابهة فوق مناطق الإكزيما. ما التشخيص العاجل؟"},"options":[{"letter":"A","en":"Eczema herpeticum","ar":"الإكزيما الهربسية"},{"letter":"B","en":"Simple contact dermatitis","ar":"التهاب جلد تلامسي بسيط"},{"letter":"C","en":"Flat warts","ar":"ثآليل مسطحة"},{"letter":"D","en":"Tinea versicolor","ar":"النخالية المبرقشة"}],"correct":"A","explanation":{"en":"Disseminated monomorphic HSV lesions on atopic skin with systemic illness indicate eczema herpeticum.","ar":"تشير آفات HSV المتشابهة المنتشرة فوق جلد تأتبي مع أعراض جهازية إلى الإكزيما الهربسية."},"reasoning":{"en":"This is not a routine eczema flare; systemic antiviral therapy must not be delayed.","ar":"هذه ليست نوبة إكزيما عادية، ويجب عدم تأخير العلاج الجهازي المضاد للفيروسات."},"image":null},{"id":"Q059","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Case","difficulty":"Easy","source":"PDF p. 106","question":{"en":"A sexually active adult has painful grouped genital vesicles, dysuria, and tender inguinal nodes. Which diagnosis is most likely?","ar":"بالغ نشط جنسيًا لديه حويصلات تناسلية مؤلمة متجمعة وعسر تبول وعقد أربية مؤلمة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Genital herpes","ar":"الهربس التناسلي"},{"letter":"B","en":"Primary syphilitic chancre","ar":"قرحة الزهري الأولية"},{"letter":"C","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"D","en":"Tinea cruris","ar":"تينيا الفخذ"}],"correct":"A","explanation":{"en":"Painful grouped vesicles or ulcers with dysuria and tender nodes are typical of genital HSV.","ar":"الحويصلات أو القرح المؤلمة المتجمعة مع عسر التبول والعقد المؤلمة نموذجية للهربس التناسلي."},"reasoning":{"en":"Pain and grouped vesicles argue against a painless chancre and distinguish HSV from nonulcerative papular conditions.","ar":"الألم والحويصلات المتجمعة لا يتوافقان مع قرحة الزهري غير المؤلمة ويميزان HSV عن الحالات الحطاطية غير المتقرحة."},"image":null},{"id":"Q060","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Case","difficulty":"Easy","source":"PDF p. 108","question":{"en":"A patient has six severe cold-sore outbreaks each year that disrupt work despite correct episodic therapy. What strategy is most appropriate?","ar":"مريض لديه ست نوبات شديدة من قرح البرد سنويًا تؤثر في عمله رغم العلاج النوباتي الصحيح. ما الاستراتيجية الأنسب؟"},"options":[{"letter":"A","en":"Daily suppressive antiviral therapy","ar":"علاج يومي مضاد للفيروسات للوقاية"},{"letter":"B","en":"Daily oral antibiotic","ar":"مضاد حيوي فموي يومي"},{"letter":"C","en":"Topical steroid alone","ar":"كورتيزون موضعي فقط"},{"letter":"D","en":"No counseling or treatment","ar":"لا توعية ولا علاج"}],"correct":"A","explanation":{"en":"Frequent or severe recurrences are an indication to consider suppressive acyclovir or valacyclovir.","ar":"تُعد النوبات المتكررة أو الشديدة سببًا للنظر في أسيكلوفير أو فالاسيكلوفير الوقائي."},"reasoning":{"en":"Suppressive therapy reduces recurrence frequency and burden when episodic treatment is insufficient.","ar":"يقلل العلاج الوقائي تكرار النوبات وعبئها عندما لا يكفي العلاج النوباتي."},"image":null},{"id":"Q061","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Case","difficulty":"Medium","source":"PDF p. 109","question":{"en":"A 10-day-old neonate has lethargy, vesicles, seizures, and elevated transaminases. What should be done immediately while PCR results are pending?","ar":"رضيع عمره 10 أيام لديه خمول وحويصلات وتشنجات وارتفاع إنزيمات الكبد. ما الإجراء الفوري أثناء انتظار PCR؟"},"options":[{"letter":"A","en":"Start empiric IV acyclovir","ar":"بدء أسيكلوفير وريدي تجريبيًا"},{"letter":"B","en":"Wait for culture confirmation without treatment","ar":"انتظار المزرعة دون علاج"},{"letter":"C","en":"Give topical salicylic acid","ar":"إعطاء حمض الساليسيليك موضعيًا"},{"letter":"D","en":"Use aspirin for fever","ar":"استخدام الأسبرين للحمى"}],"correct":"A","explanation":{"en":"Suspected neonatal HSV requires immediate high-dose IV acyclovir because delay increases mortality and neurologic injury.","ar":"يتطلب الاشتباه في HSV الوليدي بدء أسيكلوفير وريدي بجرعة عالية فورًا لأن التأخير يزيد الوفيات والضرر العصبي."},"reasoning":{"en":"The combination of vesicles, neurologic signs, and hepatitis is sufficient to treat before confirmation.","ar":"اجتماع الحويصلات والعلامات العصبية والتهاب الكبد كافٍ لبدء العلاج قبل التأكيد."},"image":null},{"id":"Q062","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Case","difficulty":"Medium","source":"PDF p. 114","question":{"en":"An unvaccinated 7-year-old has fever and intensely itchy lesions in multiple stages, concentrated on the trunk. What is the diagnosis?","ar":"طفل غير مطعم عمره 7 سنوات لديه حمى وآفات شديدة الحكة بمراحل متعددة تتركز على الجذع. ما التشخيص؟"},"options":[{"letter":"A","en":"Varicella","ar":"الجديري المائي"},{"letter":"B","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"C","en":"Common warts","ar":"ثآليل شائعة"},{"letter":"D","en":"Rubella","ar":"الحصبة الألمانية"}],"correct":"A","explanation":{"en":"Crops of lesions in different stages with a centripetal distribution are classic for varicella.","ar":"دفعات الآفات بمراحل مختلفة مع توزيع مركزي نموذجية للجديري المائي."},"reasoning":{"en":"Zoster is dermatomal and unilateral, while varicella is generalized and polymorphic.","ar":"الحزام الناري قطاعي وأحادي الجانب، بينما الجديري المائي منتشر ومتعدد المراحل."},"image":null},{"id":"Q063","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Case","difficulty":"Medium","source":"PDF p. 115","question":{"en":"An adult with chickenpox develops dyspnea, dry cough, tachypnea, and bilateral diffuse infiltrates four days after the rash. What complication is most likely?","ar":"بالغ مصاب بالجديري المائي أصيب بضيق نفس وسعال جاف وتسرع تنفس وارتشاحات ثنائية منتشرة بعد أربعة أيام من الطفح. ما المضاعفة الأرجح؟"},"options":[{"letter":"A","en":"Varicella pneumonia","ar":"التهاب رئوي بسبب الجديري"},{"letter":"B","en":"Postherpetic neuralgia","ar":"ألم عصبي تالٍ للهربس"},{"letter":"C","en":"Plantar wart","ar":"ثؤلول أخمصي"},{"letter":"D","en":"Molluscum dermatitis","ar":"التهاب جلد حول المليساء"}],"correct":"A","explanation":{"en":"Varicella pneumonia is a major adult complication and typically develops within days of rash onset.","ar":"يُعد التهاب الرئة بالجديري مضاعفة مهمة لدى البالغين ويظهر عادةً خلال أيام من الطفح."},"reasoning":{"en":"Respiratory symptoms plus diffuse infiltrates require urgent IV acyclovir and hospital assessment.","ar":"تستلزم الأعراض التنفسية مع الارتشاحات المنتشرة تقييمًا بالمستشفى وأسيكلوفير وريديًا بصورة عاجلة."},"image":null},{"id":"Q064","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Case","difficulty":"Medium","source":"PDF p. 115","question":{"en":"A child with chickenpox becomes confused and vomits after receiving aspirin for fever. What complication should be suspected?","ar":"طفل مصاب بالجديري أصبح مشوشًا ويتقيأ بعد إعطائه أسبرين للحمى. ما المضاعفة المشتبه بها؟"},"options":[{"letter":"A","en":"Reye syndrome","ar":"متلازمة راي"},{"letter":"B","en":"Ramsay Hunt syndrome","ar":"متلازمة رامزي هانت"},{"letter":"C","en":"Congenital rubella syndrome","ar":"متلازمة الحصبة الألمانية الخلقية"},{"letter":"D","en":"Aplastic crisis","ar":"أزمة لاتنسجية"}],"correct":"A","explanation":{"en":"Encephalopathy and vomiting after salicylate exposure during a viral illness suggest Reye syndrome.","ar":"يوحي الاعتلال الدماغي والقيء بعد التعرض للساليسيلات أثناء مرض فيروسي بمتلازمة راي."},"reasoning":{"en":"Medication history is the decisive clue and reinforces why aspirin is avoided in febrile children.","ar":"التاريخ الدوائي هو الدليل الحاسم ويؤكد سبب تجنب الأسبرين لدى الأطفال المصابين بالحمى."},"image":null},{"id":"Q065","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Case","difficulty":"Medium","source":"PDF p. 116","question":{"en":"A healthy 8-year-old presents 36 hours after an uncomplicated chickenpox rash began. The child is drinking normally and has no risk factors. What is the best management?","ar":"طفل سليم عمره 8 سنوات حضر بعد 36 ساعة من بدء طفح جديري غير معقد، ويتناول السوائل طبيعيًا ولا توجد عوامل خطورة. ما التدبير الأفضل؟"},"options":[{"letter":"A","en":"Supportive care without routine antiviral therapy","ar":"رعاية داعمة دون مضاد فيروسات روتيني"},{"letter":"B","en":"Mandatory IV acyclovir","ar":"أسيكلوفير وريدي إلزامي"},{"letter":"C","en":"Aspirin every six hours","ar":"أسبرين كل ست ساعات"},{"letter":"D","en":"Broad-spectrum antibiotics for all lesions","ar":"مضادات حيوية واسعة لكل الآفات"}],"correct":"A","explanation":{"en":"Routine antivirals provide only modest benefit in low-risk immunocompetent children and are not generally required.","ar":"تقدم مضادات الفيروسات فائدة محدودة لدى الأطفال منخفضي الخطورة ذوي المناعة السليمة ولا تُطلب روتينيًا."},"reasoning":{"en":"Host risk and complications, not the presence of rash alone, determine antiviral need.","ar":"تحدد خطورة المريض والمضاعفات الحاجة للمضاد الفيروسي وليس وجود الطفح وحده."},"image":null},{"id":"Q066","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Case","difficulty":"Medium","source":"PDF p. 117","question":{"en":"A child receiving chemotherapy develops generalized active varicella lesions and fever. What is the preferred initial treatment?","ar":"طفل يتلقى علاجًا كيماويًا أصيب بآفات جديري نشطة منتشرة وحمى. ما العلاج الأولي المفضل؟"},"options":[{"letter":"A","en":"IV acyclovir with hospital monitoring","ar":"أسيكلوفير وريدي مع المتابعة بالمستشفى"},{"letter":"B","en":"Observation only","ar":"الملاحظة فقط"},{"letter":"C","en":"Topical imiquimod","ar":"إيميكويمود موضعي"},{"letter":"D","en":"Oral salicylic acid","ar":"حمض الساليسيليك فمويًا"}],"correct":"A","explanation":{"en":"Chemotherapy-associated immunosuppression greatly increases the risk of disseminated and visceral varicella.","ar":"يزيد تثبيط المناعة بسبب العلاج الكيماوي خطر الجديري المنتشر والحشوي بدرجة كبيرة."},"reasoning":{"en":"Active lesions and systemic illness in an immunocompromised child require reliable IV antiviral exposure.","ar":"تستلزم الآفات النشطة والأعراض الجهازية لدى طفل مثبط المناعة علاجًا وريديًا موثوقًا."},"image":null},{"id":"Q067","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Case","difficulty":"Medium","source":"PDF p. 120","question":{"en":"A 67-year-old has burning pain followed two days later by grouped vesicles over one thoracic dermatome that do not cross the midline. What is the diagnosis?","ar":"مريض عمره 67 عامًا لديه ألم حارق تبعته بعد يومين حويصلات متجمعة ضمن قطاع صدري واحد لا تعبر الخط المتوسط. ما التشخيص؟"},"options":[{"letter":"A","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"B","en":"Varicella","ar":"الجديري المائي"},{"letter":"C","en":"Measles","ar":"الحصبة"},{"letter":"D","en":"Molluscum contagiosum","ar":"المليساء المعدية"}],"correct":"A","explanation":{"en":"A painful unilateral dermatomal vesicular eruption is diagnostic of herpes zoster in a typical case.","ar":"الطفح الحويصلي المؤلم أحادي الجانب ضمن قطاع عصبي يُشخص الحزام الناري في الحالة النموذجية."},"reasoning":{"en":"Age, prodromal neuropathic pain, and midline-respecting distribution fit VZV reactivation.","ar":"العمر والألم العصبي البادري والتوزيع الذي يحترم الخط المتوسط تتوافق مع إعادة تنشيط VZV."},"image":null},{"id":"Q068","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Case","difficulty":"Medium","source":"PDF p. 121","question":{"en":"A patient with forehead zoster has vesicles on the nasal tip and complains of blurred vision. What is the next priority?","ar":"مريض بحزام ناري في الجبهة لديه حويصلات على طرف الأنف ويشكو من تشوش الرؤية. ما الأولوية التالية؟"},"options":[{"letter":"A","en":"Urgent ophthalmology assessment plus systemic antiviral therapy","ar":"تقييم عاجل للعيون مع علاج جهازي مضاد للفيروسات"},{"letter":"B","en":"Reassure and review after one month","ar":"الطمأنة والمراجعة بعد شهر"},{"letter":"C","en":"Apply salicylic acid near the eye","ar":"وضع حمض الساليسيليك قرب العين"},{"letter":"D","en":"Treat only with an antihistamine","ar":"العلاج بمضاد هيستامين فقط"}],"correct":"A","explanation":{"en":"Nasal-tip lesions and visual symptoms suggest herpes zoster ophthalmicus with possible ocular involvement.","ar":"تشير آفات طرف الأنف والأعراض البصرية إلى هربس عيني مع احتمال إصابة العين."},"reasoning":{"en":"Vision can be threatened; referral and antiviral therapy should occur immediately, not after observation.","ar":"قد يتهدد البصر، لذا يلزم التحويل والعلاج المضاد للفيروسات فورًا لا بعد الملاحظة."},"image":null},{"id":"Q069","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Case","difficulty":"Medium","source":"PDF p. 121","question":{"en":"An older adult has severe ear pain, vesicles in the external auditory canal, vertigo, and ipsilateral facial weakness. What syndrome is present?","ar":"مسن لديه ألم شديد بالأذن وحويصلات بالقناة السمعية ودوار وضعف بالوجه في الجهة نفسها. ما المتلازمة؟"},"options":[{"letter":"A","en":"Ramsay Hunt syndrome","ar":"متلازمة رامزي هانت"},{"letter":"B","en":"Herpetic gingivostomatitis","ar":"التهاب الفم واللثة الهربسي"},{"letter":"C","en":"Fifth disease","ar":"المرض الخامس"},{"letter":"D","en":"Varicella pneumonia","ar":"التهاب رئوي بالجديري"}],"correct":"A","explanation":{"en":"Zoster oticus affecting the facial nerve produces the Ramsay Hunt syndrome pattern.","ar":"يسبب الحزام الناري الأذني مع إصابة العصب الوجهي نمط متلازمة رامزي هانت."},"reasoning":{"en":"Ear vesicles plus facial palsy distinguish it from Bell palsy without vesicles.","ar":"تميز حويصلات الأذن مع شلل الوجه الحالة عن شلل بيل دون حويصلات."},"image":null},{"id":"Q070","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Case","difficulty":"Medium","source":"PDF p. 120","question":{"en":"A 72-year-old reports persistent burning and allodynia four months after the zoster rash healed. What is the diagnosis?","ar":"مريض عمره 72 عامًا يشكو من حرقان مستمر وألم عند اللمس بعد أربعة أشهر من شفاء طفح الحزام الناري. ما التشخيص؟"},"options":[{"letter":"A","en":"Postherpetic neuralgia","ar":"الألم العصبي التالي للهربس"},{"letter":"B","en":"Active varicella","ar":"جديري مائي نشط"},{"letter":"C","en":"Acute urticaria","ar":"شرى حاد"},{"letter":"D","en":"Common wart","ar":"ثؤلول شائع"}],"correct":"A","explanation":{"en":"Neuropathic pain persisting beyond 90 days after zoster meets the definition of PHN.","ar":"الألم العصبي المستمر أكثر من 90 يومًا بعد الحزام الناري يحقق تعريف الألم العصبي التالي للهربس."},"reasoning":{"en":"Timing and neuropathic quality distinguish PHN from ongoing skin infection.","ar":"يميز التوقيت والطبيعة العصبية الألم التالي للهربس عن استمرار عدوى جلدية."},"image":null},{"id":"Q071","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Case","difficulty":"Medium","source":"PDF p. 121","question":{"en":"An immunocompromised patient with zoster develops dozens of vesicles outside the original dermatome and confusion. What is the most likely concern?","ar":"مريض مثبط المناعة بالحزام الناري ظهرت لديه عشرات الحويصلات خارج القطاع الأصلي مع تشوش. ما القلق الأرجح؟"},"options":[{"letter":"A","en":"Disseminated zoster with possible CNS involvement","ar":"حزام ناري منتشر مع احتمال إصابة الجهاز العصبي المركزي"},{"letter":"B","en":"Simple localized zoster","ar":"حزام ناري موضعي بسيط"},{"letter":"C","en":"Only allergic contact dermatitis","ar":"التهاب جلد تلامسي فقط"},{"letter":"D","en":"Flat warts","ar":"ثآليل مسطحة"}],"correct":"A","explanation":{"en":"Spread beyond contiguous dermatomes with neurologic symptoms suggests disseminated and visceral disease.","ar":"الانتشار خارج القطاعات المتجاورة مع أعراض عصبية يشير إلى مرض منتشر وحشوي."},"reasoning":{"en":"This is life-threatening and requires hospitalization, airborne precautions, and IV acyclovir.","ar":"هذه حالة مهددة للحياة وتحتاج دخول المستشفى واحتياطات هوائية وأسيكلوفير وريدي."},"image":null},{"id":"Q072","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Case","difficulty":"Medium","source":"PDF p. 120","question":{"en":"A patient has severe dermatomal burning pain but no visible rash. Other causes are excluded and VZV PCR supports reactivation. What is this called?","ar":"مريض لديه ألم حارق شديد ضمن قطاع عصبي دون طفح ظاهر، واستُبعدت الأسباب الأخرى وأيد PCR إعادة تنشيط VZV. ما اسم الحالة؟"},"options":[{"letter":"A","en":"Zoster sine herpete","ar":"الحزام الناري دون طفح"},{"letter":"B","en":"Eczema herpeticum","ar":"الإكزيما الهربسية"},{"letter":"C","en":"Herpangina","ar":"الهربانجينا"},{"letter":"D","en":"Molluscum contagiosum","ar":"المليساء المعدية"}],"correct":"A","explanation":{"en":"VZV reactivation can rarely produce neuropathic pain without a cutaneous eruption.","ar":"قد تسبب إعادة تنشيط VZV نادرًا ألمًا عصبيًا دون طفح جلدي."},"reasoning":{"en":"The diagnosis requires careful exclusion of other causes because the usual visual clue is absent.","ar":"يحتاج التشخيص استبعادًا دقيقًا للأسباب الأخرى لغياب العلامة البصرية المعتادة."},"image":null},{"id":"Q073","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Case","difficulty":"Medium","source":"PDF p. 124","question":{"en":"A patient started oral valacyclovir for localized zoster but develops new widespread vesicles and fever after 48 hours. What is the best escalation?","ar":"مريض بدأ فالاسيكلوفير فمويًا لحزام ناري موضعي ثم ظهرت حويصلات منتشرة جديدة وحمى بعد 48 ساعة. ما التصعيد الأنسب؟"},"options":[{"letter":"A","en":"Switch to IV acyclovir and reassess for dissemination","ar":"التحويل إلى أسيكلوفير وريدي وتقييم الانتشار"},{"letter":"B","en":"Stop all antivirals","ar":"إيقاف كل مضادات الفيروسات"},{"letter":"C","en":"Add salicylic acid to vesicles","ar":"إضافة حمض الساليسيليك للحويصلات"},{"letter":"D","en":"Wait until every lesion crusts","ar":"الانتظار حتى تتقشر كل الآفات"}],"correct":"A","explanation":{"en":"Progression on oral therapy with systemic signs suggests complicated disease and inadequate outpatient management.","ar":"التقدم أثناء العلاج الفموي مع علامات جهازية يوحي بمرض معقد وعدم كفاية العلاج الخارجي."},"reasoning":{"en":"IV therapy provides dependable levels while complications and immune status are evaluated.","ar":"يوفر العلاج الوريدي مستويات موثوقة أثناء تقييم المضاعفات والحالة المناعية."},"image":null},{"id":"Q074","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Case","difficulty":"Medium","source":"PDF p. 129","question":{"en":"A teenager has a rough papule on a finger that interrupts skin lines and shows black dots after gentle paring. What is it?","ar":"مراهق لديه حطاطة خشنة على إصبع تقطع خطوط الجلد وتظهر نقاطًا سوداء بعد كشط لطيف. ما هي؟"},"options":[{"letter":"A","en":"Common wart","ar":"ثؤلول شائع"},{"letter":"B","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"C","en":"Herpes simplex","ar":"الهربس البسيط"},{"letter":"D","en":"Rubella","ar":"الحصبة الألمانية"}],"correct":"A","explanation":{"en":"A rough hyperkeratotic papule with interrupted dermatoglyphics and thrombosed capillary dots is a common wart.","ar":"الحطاطة الخشنة المتقرنة التي تقطع خطوط الجلد وبها نقاط شعيرية متخثرة هي ثؤلول شائع."},"reasoning":{"en":"The vascular dots distinguish a wart from callus, while central umbilication would favor molluscum.","ar":"تميز النقاط الوعائية الثؤلول عن الكالو، بينما يرجح التنقر المركزي المليساء."},"image":null},{"id":"Q075","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Case","difficulty":"Medium","source":"PDF p. 130","question":{"en":"A runner has a painful hyperkeratotic lesion on the sole; pain is worse with side-to-side squeezing and paring reveals pinpoint bleeding. What is the diagnosis?","ar":"عداء لديه آفة متقرنة مؤلمة في أخمص القدم، يزداد الألم بالضغط من الجانبين ويكشف الكشط نزفًا نقطيًا. ما التشخيص؟"},"options":[{"letter":"A","en":"Plantar wart","ar":"ثؤلول أخمصي"},{"letter":"B","en":"Simple corn","ar":"مسمار قدم بسيط"},{"letter":"C","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"D","en":"Molluscum contagiosum","ar":"المليساء المعدية"}],"correct":"A","explanation":{"en":"Lateral pressure pain and pinpoint bleeding after paring strongly favor a plantar wart.","ar":"الألم بالضغط الجانبي والنزف النقطي بعد الكشط يرجحان بقوة الثؤلول الأخمصي."},"reasoning":{"en":"A corn usually preserves skin lines and is more tender to direct vertical pressure.","ar":"يحافظ مسمار القدم عادةً على خطوط الجلد ويكون الألم أكبر مع الضغط العمودي المباشر."},"image":null},{"id":"Q076","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Case","difficulty":"Medium","source":"PDF p. 130","question":{"en":"A child has many tiny smooth flat-topped papules arranged along scratch marks on the face. What is the diagnosis?","ar":"طفل لديه حطاطات صغيرة ملساء كثيرة مسطحة القمة مصطفة على خطوط الخدش في الوجه. ما التشخيص؟"},"options":[{"letter":"A","en":"Flat warts with Koebnerization","ar":"ثآليل مسطحة مع ظاهرة كوبنر"},{"letter":"B","en":"Varicella","ar":"الجديري المائي"},{"letter":"C","en":"Eczema herpeticum","ar":"الإكزيما الهربسية"},{"letter":"D","en":"Measles","ar":"الحصبة"}],"correct":"A","explanation":{"en":"Flat warts commonly affect the face and may spread along trauma by autoinoculation.","ar":"تشيع الثآليل المسطحة على الوجه وقد تنتشر على مسار الرضوض بالعدوى الذاتية."},"reasoning":{"en":"Smooth flat morphology and linear distribution distinguish them from vesicular or maculopapular rashes.","ar":"يميز الشكل الأملس المسطح والتوزيع الخطي هذه الآفات عن الطفوح الحويصلية أو البقعية الحطاطية."},"image":null},{"id":"Q077","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Case","difficulty":"Medium","source":"PDF p. 128","question":{"en":"A patient has soft, moist, cauliflower-like lesions around the anus. Which diagnosis is most likely?","ar":"مريض لديه آفات لينة رطبة تشبه القرنبيط حول الشرج. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Condyloma acuminata","ar":"الثآليل التناسلية"},{"letter":"B","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"C","en":"Herpetic whitlow","ar":"الداحس الهربسي"},{"letter":"D","en":"Fifth disease","ar":"المرض الخامس"}],"correct":"A","explanation":{"en":"The described papillomatous genital morphology is typical of HPV-associated condyloma acuminata.","ar":"الشكل الحليمي التناسلي الموصوف نموذجي للثآليل التناسلية المرتبطة بـHPV."},"reasoning":{"en":"A complete sexual-health evaluation is appropriate because visible warts may coexist with other infections.","ar":"يكون تقييم الصحة الجنسية كاملًا مناسبًا لأن الثآليل الظاهرة قد تتزامن مع عدوى أخرى."},"image":null},{"id":"Q078","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Case","difficulty":"Medium","source":"PDF p. 133","question":{"en":"A pigmented, ulcerated, rapidly enlarging “wart” does not respond to standard therapy. What is the most appropriate next step?","ar":"آفة مصطبغة متقرحة سريعة النمو وُصفت كثؤلول ولم تستجب للعلاج المعتاد. ما الخطوة الأنسب؟"},"options":[{"letter":"A","en":"Biopsy to exclude malignancy","ar":"خزعة لاستبعاد ورم خبيث"},{"letter":"B","en":"Continue blind treatment indefinitely","ar":"استمرار العلاج العشوائي بلا نهاية"},{"letter":"C","en":"Start acyclovir","ar":"بدء أسيكلوفير"},{"letter":"D","en":"Apply a potent steroid alone","ar":"وضع كورتيزون قوي فقط"}],"correct":"A","explanation":{"en":"Atypical, ulcerated, pigmented, or treatment-resistant lesions require histologic confirmation.","ar":"تحتاج الآفات غير النمطية أو المتقرحة أو المصطبغة أو المقاومة للعلاج تأكيدًا نسيجيًا."},"reasoning":{"en":"Failure to reconsider the diagnosis risks missing squamous carcinoma or another serious condition.","ar":"عدم إعادة النظر في التشخيص قد يؤدي إلى تفويت سرطان حرشفي أو حالة خطيرة أخرى."},"image":null},{"id":"Q079","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Case","difficulty":"Medium","source":"PDF p. 132","question":{"en":"A pregnant patient has external genital warts. Which treatment should be avoided because of potential fetal toxicity?","ar":"مريضة حامل لديها ثآليل تناسلية خارجية. أي علاج ينبغي تجنبه لاحتمال السمية الجنينية؟"},"options":[{"letter":"A","en":"Podophyllin/podophyllotoxin","ar":"بودوفيلين أو بودوفيلوتوكسين"},{"letter":"B","en":"Provider-applied cryotherapy","ar":"التبريد بواسطة مقدم الرعاية"},{"letter":"C","en":"Trichloroacetic acid applied by a clinician","ar":"حمض ثلاثي كلورو الأسيتيك بواسطة الطبيب"},{"letter":"D","en":"Observation when appropriate","ar":"الملاحظة عند ملاءمتها"}],"correct":"A","explanation":{"en":"Podophyllin compounds are contraindicated in pregnancy; safer provider-applied options are preferred.","ar":"تُمنع مركبات البودوفيلين في الحمل وتُفضل الخيارات الآمنة التي يطبقها مقدم الرعاية."},"reasoning":{"en":"Pregnancy status is essential before selecting patient-applied wart medicines.","ar":"معرفة الحمل أساسية قبل اختيار أدوية الثآليل التي يطبقها المريض."},"image":null},{"id":"Q080","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Case","difficulty":"Medium","source":"PDF p. 134","question":{"en":"An immunosuppressed transplant recipient develops numerous rapidly recurring warts. What explains the difficult course?","ar":"مريض زرع مثبط المناعة ظهرت لديه ثآليل كثيرة سريعة النكس. ما تفسير صعوبة المسار؟"},"options":[{"letter":"A","en":"Reduced cell-mediated control of HPV","ar":"ضعف السيطرة المناعية الخلوية على HPV"},{"letter":"B","en":"Excess vitamin A","ar":"زيادة فيتامين أ"},{"letter":"C","en":"Acyclovir resistance","ar":"مقاومة أسيكلوفير"},{"letter":"D","en":"Acute bacterial toxin production","ar":"إنتاج سم بكتيري حاد"}],"correct":"A","explanation":{"en":"Cell-mediated immunity is critical for controlling HPV, so immunosuppression increases burden and recurrence.","ar":"المناعة الخلوية ضرورية للسيطرة على HPV، لذا يزيد تثبيط المناعة عدد الآفات والنكس."},"reasoning":{"en":"The host immune state often predicts persistence more strongly than the individual destructive procedure used.","ar":"تتنبأ حالة المناعة بالاستمرار أكثر من نوع الإجراء التدميري المستخدم في كثير من الأحيان."},"image":null},{"id":"Q081","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Case","difficulty":"Medium","source":"PDF p. 138","question":{"en":"A 4-year-old has fever, painful oral ulcers, and small vesicles on palms, soles, and buttocks. What is the diagnosis?","ar":"طفل عمره 4 سنوات لديه حمى وقرح فموية مؤلمة وحويصلات صغيرة على الكفين والأخمصين والأرداف. ما التشخيص؟"},"options":[{"letter":"A","en":"Hand-foot-and-mouth disease","ar":"مرض اليد والقدم والفم"},{"letter":"B","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"C","en":"Rubella","ar":"الحصبة الألمانية"},{"letter":"D","en":"Common warts","ar":"ثآليل شائعة"}],"correct":"A","explanation":{"en":"The oral-acral distribution in a young child is classic for HFMD.","ar":"التوزيع الفموي الطرفي لدى طفل صغير نموذجي لمرض اليد والقدم والفم."},"reasoning":{"en":"Palmar and plantar lesions plus oral ulcers are much more specific than fever alone.","ar":"آفات الكفين والأخمصين مع القرح الفموية أكثر نوعية بكثير من الحمى وحدها."},"image":null},{"id":"Q082","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Case","difficulty":"Medium","source":"PDF p. 139","question":{"en":"A child has high fever and painful vesicles confined to the soft palate and posterior pharynx, with no hand or foot lesions. What is the likely diagnosis?","ar":"طفل لديه حمى مرتفعة وحويصلات مؤلمة محصورة بالحنك الرخو وخلف البلعوم دون آفات باليدين أو القدمين. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Herpangina","ar":"الهربانجينا"},{"letter":"B","en":"HFMD with classic acral rash","ar":"مرض اليد والقدم والفم بالنمط المعتاد"},{"letter":"C","en":"Varicella","ar":"الجديري المائي"},{"letter":"D","en":"Genital herpes","ar":"الهربس التناسلي"}],"correct":"A","explanation":{"en":"Posterior oral vesicles without an acral eruption favor herpangina.","ar":"ترجح الحويصلات الفموية الخلفية دون طفح طرفي تشخيص الهربانجينا."},"reasoning":{"en":"Lesion location and absence of hand-foot involvement are the key discriminators.","ar":"مكان الآفات وغياب إصابة اليد والقدم هما العاملان الفارقان."},"image":null},{"id":"Q083","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Case","difficulty":"Medium","source":"PDF p. 141","question":{"en":"A toddler with HFMD refuses fluids because of oral pain and has reduced urine output. What is the immediate management priority?","ar":"طفل صغير مصاب بمرض اليد والقدم والفم يرفض السوائل بسبب ألم الفم وقل البول. ما أولوية التدبير الفورية؟"},"options":[{"letter":"A","en":"Assess and correct dehydration while controlling pain","ar":"تقييم وعلاج الجفاف مع السيطرة على الألم"},{"letter":"B","en":"Remove every vesicle surgically","ar":"استئصال كل حويصلة جراحيًا"},{"letter":"C","en":"Start wart therapy","ar":"بدء علاج الثآليل"},{"letter":"D","en":"Give aspirin","ar":"إعطاء الأسبرين"}],"correct":"A","explanation":{"en":"Dehydration from painful stomatitis is a common practical complication of HFMD.","ar":"الجفاف بسبب التهاب الفم المؤلم مضاعفة عملية شائعة لمرض اليد والقدم والفم."},"reasoning":{"en":"Restoring intake or providing rehydration takes priority over treating a self-limited skin eruption.","ar":"استعادة تناول السوائل أو إعطاء الإماهة أولوية على علاج طفح جلدي محدود ذاتيًا."},"image":null},{"id":"Q084","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Case","difficulty":"Medium","source":"PDF p. 140","question":{"en":"A child with HFMD develops lethargy, repeated startle-like jerks, tachycardia, and respiratory distress. What should be suspected?","ar":"طفل بمرض اليد والقدم والفم أصيب بخمول ونفضات متكررة شبيهة بالفزع وتسرع قلب وضيق نفس. ما المشتبه؟"},"options":[{"letter":"A","en":"Severe enterovirus disease with neurologic/cardiopulmonary involvement","ar":"مرض معوي فيروسي شديد مع إصابة عصبية وقلبية رئوية"},{"letter":"B","en":"Simple uncomplicated HFMD","ar":"مرض يد وقدم وفم بسيط"},{"letter":"C","en":"Isolated molluscum","ar":"مليساء منفردة"},{"letter":"D","en":"Flat warts","ar":"ثآليل مسطحة"}],"correct":"A","explanation":{"en":"Neurologic and autonomic or cardiopulmonary signs are red flags, particularly in EV-A71 infection.","ar":"العلامات العصبية واللاإرادية أو القلبية الرئوية إنذارات خطرة خاصة مع EV-A71."},"reasoning":{"en":"The child requires urgent hospital evaluation rather than routine home supportive care.","ar":"يحتاج الطفل تقييمًا عاجلًا بالمستشفى بدل الرعاية المنزلية الداعمة المعتادة."},"image":null},{"id":"Q085","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Case","difficulty":"Medium","source":"PDF p. 143","question":{"en":"Several children in a nursery develop HFMD. Which control measure is most important?","ar":"ظهرت حالات مرض اليد والقدم والفم لدى عدة أطفال في حضانة. ما أهم إجراء للسيطرة؟"},"options":[{"letter":"A","en":"Hand hygiene, cleaning shared surfaces, and excluding severely ill children","ar":"نظافة اليدين وتنظيف الأسطح المشتركة وإبعاد الأطفال شديدي المرض"},{"letter":"B","en":"Mass acyclovir prophylaxis","ar":"وقاية جماعية بأسيكلوفير"},{"letter":"C","en":"Destroy all toys permanently","ar":"التخلص الدائم من كل الألعاب"},{"letter":"D","en":"Give antibiotics to all contacts","ar":"إعطاء مضادات حيوية لكل المخالطين"}],"correct":"A","explanation":{"en":"Enteroviruses spread through respiratory secretions, vesicle fluid, and the fecal-oral route.","ar":"تنتقل الفيروسات المعوية عبر الإفرازات التنفسية وسائل الحويصلات والطريق البرازي الفموي."},"reasoning":{"en":"Hygiene and environmental cleaning target the actual routes of transmission; antibiotics do not.","ar":"تستهدف النظافة وتنظيف البيئة طرق الانتقال الفعلية، بينما لا تفيد المضادات الحيوية."},"image":null},{"id":"Q086","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Case","difficulty":"Hard","source":"PDF p. 147","question":{"en":"An unvaccinated child has high fever, cough, coryza, conjunctivitis, and tiny bluish-white buccal spots. What is the diagnosis?","ar":"طفل غير مطعم لديه حمى مرتفعة وسعال ورشح والتهاب ملتحمة ونقاط فموية صغيرة بيضاء مزرقة. ما التشخيص؟"},"options":[{"letter":"A","en":"Measles","ar":"الحصبة"},{"letter":"B","en":"Rubella","ar":"الحصبة الألمانية"},{"letter":"C","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"D","en":"Herpes zoster","ar":"الحزام الناري"}],"correct":"A","explanation":{"en":"The prodromal “three Cs” plus Koplik spots are characteristic of measles.","ar":"الأعراض الثلاثة البادرية مع بقع كوبليك مميزة للحصبة."},"reasoning":{"en":"Diagnosis should trigger immediate airborne isolation and public-health notification.","ar":"يجب أن يؤدي التشخيص إلى العزل الهوائي الفوري وإبلاغ الصحة العامة."},"image":null},{"id":"Q087","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Case","difficulty":"Hard","source":"PDF p. 148","question":{"en":"Two days after cough, coryza, conjunctivitis, and Koplik spots, a rash begins at the hairline and spreads downward. What rash is this?","ar":"بعد يومين من السعال والرشح والتهاب الملتحمة وبقع كوبليك بدأ طفح عند خط الشعر وانتشر إلى أسفل. ما هذا الطفح؟"},"options":[{"letter":"A","en":"Measles exanthem","ar":"طفح الحصبة"},{"letter":"B","en":"Zoster eruption","ar":"طفح الحزام الناري"},{"letter":"C","en":"Molluscum","ar":"المليساء"},{"letter":"D","en":"Plantar warts","ar":"الثآليل الأخمصية"}],"correct":"A","explanation":{"en":"Cephalocaudal spread of a confluent maculopapular rash after the measles prodrome is classic.","ar":"الانتشار من الرأس إلى أسفل لطفح بقعي حطاطي متلاحم بعد الطور البادري للحصبة نمطي."},"reasoning":{"en":"The chronological sequence is as important as lesion morphology.","ar":"التسلسل الزمني مهم بقدر شكل الآفات."},"image":null},{"id":"Q088","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Case","difficulty":"Hard","source":"PDF p. 150","question":{"en":"A malnourished child with measles develops worsening cough, hypoxia, and secondary bacterial pneumonia. Which principle is correct?","ar":"طفل مصاب بسوء تغذية وحصبة أصيب بسعال متزايد ونقص أكسجة والتهاب رئوي بكتيري ثانوي. أي مبدأ صحيح؟"},"options":[{"letter":"A","en":"Treat the bacterial complication and provide measles supportive care including vitamin A","ar":"علاج المضاعفة البكتيرية مع الرعاية الداعمة للحصبة وفيتامين أ"},{"letter":"B","en":"Antibiotics cure the measles virus itself","ar":"المضادات الحيوية تشفي فيروس الحصبة نفسه"},{"letter":"C","en":"Avoid oxygen","ar":"تجنب الأكسجين"},{"letter":"D","en":"Use salicylic acid on the rash","ar":"استخدام حمض الساليسيليك على الطفح"}],"correct":"A","explanation":{"en":"Measles treatment is supportive, but proven bacterial complications require appropriate antibiotics.","ar":"علاج الحصبة داعم، لكن المضاعفات البكتيرية المؤكدة تحتاج مضادات حيوية مناسبة."},"reasoning":{"en":"The clinician must distinguish treatment of the virus from treatment of complications caused by measles-associated immune suppression.","ar":"يجب التفريق بين علاج الفيروس وعلاج المضاعفات الناتجة عن تثبيط المناعة المصاحب للحصبة."},"image":null},{"id":"Q089","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Case","difficulty":"Hard","source":"PDF p. 149","question":{"en":"A child with suspected measles arrives in a crowded clinic waiting room. What should staff do first?","ar":"وصل طفل مشتبه في إصابته بالحصبة إلى غرفة انتظار مزدحمة. ماذا يفعل الطاقم أولًا؟"},"options":[{"letter":"A","en":"Place the patient in airborne isolation immediately","ar":"وضع المريض في عزل هوائي فورًا"},{"letter":"B","en":"Wait for IgM results in the waiting room","ar":"انتظار نتيجة IgM في غرفة الانتظار"},{"letter":"C","en":"Apply topical antiviral cream","ar":"وضع كريم مضاد للفيروسات"},{"letter":"D","en":"Send the child back to school","ar":"إعادة الطفل للمدرسة"}],"correct":"A","explanation":{"en":"Suspected measles must be isolated before confirmation because airborne transmission is extremely efficient.","ar":"يجب عزل الحصبة المشتبه بها قبل التأكيد لأن الانتقال الهوائي شديد الكفاءة."},"reasoning":{"en":"Early infection-control action prevents a single case from becoming a healthcare-associated outbreak.","ar":"يمنع الإجراء المبكر لمكافحة العدوى تحول حالة واحدة إلى تفشٍ داخل المنشأة."},"image":null},{"id":"Q090","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Case","difficulty":"Hard","source":"PDF p. 152","question":{"en":"Years after recovery from measles, an adolescent develops progressive behavioral decline, myoclonus, and cognitive deterioration. What late complication is possible?","ar":"بعد سنوات من التعافي من الحصبة، أصيب مراهق بتدهور سلوكي تدريجي ورمع عضلي وتراجع معرفي. ما المضاعفة المتأخرة المحتملة؟"},"options":[{"letter":"A","en":"Subacute sclerosing panencephalitis","ar":"التهاب الدماغ الشامل المصلب تحت الحاد"},{"letter":"B","en":"Postherpetic neuralgia","ar":"الألم العصبي التالي للهربس"},{"letter":"C","en":"Ramsay Hunt syndrome","ar":"متلازمة رامزي هانت"},{"letter":"D","en":"Transient aplastic crisis","ar":"أزمة لاتنسجية عابرة"}],"correct":"A","explanation":{"en":"SSPE is a rare progressive neurologic disease occurring years after measles infection.","ar":"يُعد SSPE مرضًا عصبيًا تقدميًا نادرًا يحدث بعد سنوات من عدوى الحصبة."},"reasoning":{"en":"The long latency and progressive neurologic decline distinguish it from acute encephalitis.","ar":"تميز فترة الكمون الطويلة والتدهور العصبي التدريجي الحالة عن التهاب الدماغ الحاد."},"image":null},{"id":"Q091","topic":"rubella","topicEn":"Rubella","topicAr":"الحصبة الألمانية","type":"Case","difficulty":"Hard","source":"PDF p. 155","question":{"en":"A young adult has low-grade fever, a fine pink rash, and tender postauricular and suboccipital nodes. What is the most likely diagnosis?","ar":"بالغ شاب لديه حمى خفيفة وطفح وردي دقيق وعقد مؤلمة خلف الأذن وتحت القذال. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Rubella","ar":"الحصبة الألمانية"},{"letter":"B","en":"Measles","ar":"الحصبة"},{"letter":"C","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"D","en":"Molluscum contagiosum","ar":"المليساء المعدية"}],"correct":"A","explanation":{"en":"A mild exanthem with characteristic posterior lymphadenopathy supports rubella.","ar":"يدعم الطفح الخفيف مع تضخم العقد الخلفية المميز تشخيص الحصبة الألمانية."},"reasoning":{"en":"Unlike measles, rubella usually has a milder prodrome and lacks prominent cough, coryza, and conjunctivitis.","ar":"بخلاف الحصبة، تكون الأعراض البادرية أخف ولا يبرز السعال والرشح والتهاب الملتحمة."},"image":null},{"id":"Q092","topic":"rubella","topicEn":"Rubella","topicAr":"الحصبة الألمانية","type":"Case","difficulty":"Hard","source":"PDF p. 156","question":{"en":"A pregnant teacher is exposed to a child with a rubella-like rash and does not know her immune status. What is the priority?","ar":"معلمة حامل تعرضت لطفل لديه طفح شبيه بالحصبة الألمانية ولا تعرف حالتها المناعية. ما الأولوية؟"},"options":[{"letter":"A","en":"Urgent obstetric/infectious-disease assessment with rubella testing","ar":"تقييم عاجل للنساء والعدوى مع فحوص الحصبة الألمانية"},{"letter":"B","en":"Give live MMR vaccine immediately during pregnancy","ar":"إعطاء لقاح MMR الحي فورًا أثناء الحمل"},{"letter":"C","en":"Ignore the exposure","ar":"تجاهل التعرض"},{"letter":"D","en":"Start acyclovir","ar":"بدء أسيكلوفير"}],"correct":"A","explanation":{"en":"Possible rubella exposure in pregnancy requires prompt assessment because fetal risk depends on gestational age and maternal infection.","ar":"يتطلب التعرض المحتمل للحصبة الألمانية في الحمل تقييمًا سريعًا لأن خطر الجنين يعتمد على عمر الحمل وعدوى الأم."},"reasoning":{"en":"MMR is a live vaccine and is not administered during pregnancy; testing and specialist counseling are required.","ar":"لقاح MMR حي ولا يُعطى أثناء الحمل، وتلزم الفحوص والاستشارة المتخصصة."},"image":null},{"id":"Q093","topic":"fifth-disease","topicEn":"Fifth Disease","topicAr":"المرض الخامس","type":"Case","difficulty":"Hard","source":"PDF p. 158","question":{"en":"A schoolchild has bright red cheeks followed by a lacy rash on the arms and trunk but feels well. What is the diagnosis?","ar":"طفل مدرسة لديه احمرار شديد بالخدين تلاه طفح شبكي على الذراعين والجذع مع حالة عامة جيدة. ما التشخيص؟"},"options":[{"letter":"A","en":"Erythema infectiosum","ar":"الحمامى المعدية «المرض الخامس»"},{"letter":"B","en":"Varicella","ar":"الجديري المائي"},{"letter":"C","en":"Herpes simplex","ar":"الهربس البسيط"},{"letter":"D","en":"Genital warts","ar":"الثآليل التناسلية"}],"correct":"A","explanation":{"en":"The slapped-cheek phase followed by a lacy reticular rash is classic for parvovirus B19 infection.","ar":"مرحلة الخدود المصفوعة التي يتبعها طفح شبكي نموذجية لعدوى بارفو B19."},"reasoning":{"en":"By the time the rash appears, the child is often no longer in the most contagious viremic phase.","ar":"عند ظهور الطفح يكون الطفل غالبًا قد تجاوز المرحلة الفيروسية الأكثر عدوى."},"image":null},{"id":"Q094","topic":"fifth-disease","topicEn":"Fifth Disease","topicAr":"المرض الخامس","type":"Case","difficulty":"Hard","source":"PDF p. 160","question":{"en":"A patient with sickle cell disease develops sudden profound anemia and reticulocytopenia after exposure to a child with fifth disease. What happened?","ar":"مريض أنيميا منجلية أصيب بأنيميا شديدة مفاجئة ونقص الخلايا الشبكية بعد التعرض لطفل بالمرض الخامس. ما الذي حدث؟"},"options":[{"letter":"A","en":"Parvovirus B19 transient aplastic crisis","ar":"أزمة لاتنسجية عابرة بسبب بارفو B19"},{"letter":"B","en":"Postherpetic neuralgia","ar":"ألم عصبي تالٍ للهربس"},{"letter":"C","en":"Varicella pneumonia","ar":"التهاب رئوي بالجديري"},{"letter":"D","en":"HPV-associated cancer","ar":"سرطان مرتبط بـHPV"}],"correct":"A","explanation":{"en":"Parvovirus B19 temporarily suppresses erythropoiesis, causing dangerous anemia in chronic hemolytic disorders.","ar":"يثبط بارفو B19 تكون كريات الدم مؤقتًا مسببًا أنيميا خطرة في أمراض الانحلال المزمنة."},"reasoning":{"en":"Reticulocytopenia is the key clue that marrow production, not only hemolysis, has abruptly fallen.","ar":"نقص الخلايا الشبكية دليل أساسي على هبوط إنتاج النخاع وليس زيادة الانحلال فقط."},"image":null},{"id":"Q095","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"Case","difficulty":"Hard","source":"PDF p. 161","question":{"en":"A healthy 6-year-old has several painless shiny dome-shaped papules with central dimples in the elbow folds. What is the diagnosis?","ar":"طفل سليم عمره 6 سنوات لديه حطاطات لامعة قُبّبية غير مؤلمة ذات انخفاض مركزي في ثنيات المرفق. ما التشخيص؟"},"options":[{"letter":"A","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"B","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"C","en":"Measles","ar":"الحصبة"},{"letter":"D","en":"Tinea corporis","ar":"تينيا الجسم"}],"correct":"A","explanation":{"en":"Pearly umbilicated papules in flexural sites are typical of molluscum in children.","ar":"الحطاطات اللؤلؤية المنقرة في الثنيات نموذجية للمليساء لدى الأطفال."},"reasoning":{"en":"The lesions are papular and painless, unlike grouped painful herpes vesicles.","ar":"الآفات حطاطية وغير مؤلمة بخلاف حويصلات الهربس المتجمعة المؤلمة."},"image":null},{"id":"Q096","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"Case","difficulty":"Hard","source":"PDF p. 164","question":{"en":"An adult has numerous giant facial molluscum lesions and weight loss. What additional evaluation is most appropriate?","ar":"بالغ لديه آفات مليساء وجهية ضخمة عديدة مع فقدان وزن. ما التقييم الإضافي الأنسب؟"},"options":[{"letter":"A","en":"Evaluate for HIV or another immunodeficiency","ar":"التقييم لـHIV أو نقص مناعة آخر"},{"letter":"B","en":"Test only for hyperlipidemia","ar":"فحص الدهون فقط"},{"letter":"C","en":"No further evaluation","ar":"لا تقييم إضافي"},{"letter":"D","en":"Assume all lesions are acne","ar":"اعتبار كل الآفات حب شباب"}],"correct":"A","explanation":{"en":"Giant, extensive, facial molluscum in an adult is a classic clue to advanced immunosuppression.","ar":"المليساء الضخمة المنتشرة بالوجه لدى بالغ علامة كلاسيكية على تثبيط مناعي متقدم."},"reasoning":{"en":"Treating lesions alone without identifying the host problem would miss the most important diagnosis.","ar":"علاج الآفات وحدها دون كشف مشكلة المناعة يفوت التشخيص الأهم."},"image":null},{"id":"Q097","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"Case","difficulty":"Hard","source":"PDF p. 165","question":{"en":"A child scratches molluscum papules and new lesions appear in a line along the scratch. What mechanism explains this?","ar":"طفل حك حطاطات المليساء فظهرت آفات جديدة في خط الخدش. ما الآلية؟"},"options":[{"letter":"A","en":"Autoinoculation","ar":"العدوى الذاتية"},{"letter":"B","en":"Hematogenous bacterial sepsis","ar":"إنتان بكتيري دموي"},{"letter":"C","en":"Allergic photosensitivity","ar":"حساسية ضوئية"},{"letter":"D","en":"VZV latency","ar":"كمون VZV"}],"correct":"A","explanation":{"en":"Scratching transfers viral material to adjacent traumatized skin, creating linear autoinoculation.","ar":"ينقل الحك المادة الفيروسية إلى جلد مجاور متأذٍ فتظهر عدوى ذاتية خطية."},"reasoning":{"en":"Counseling to avoid picking and to cover lesions reduces spread.","ar":"تقلل التوعية بعدم العبث وتغطية الآفات من الانتشار."},"image":null},{"id":"Q098","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"Case","difficulty":"Hard","source":"PDF p. 166","question":{"en":"A young adult with mild recent COVID-19 develops tender violaceous swelling of several toes in cold weather. What pattern is this?","ar":"شاب أصيب حديثًا بكوفيد خفيف وظهر لديه تورم بنفسجي مؤلم في عدة أصابع قدم في الطقس البارد. ما النمط؟"},"options":[{"letter":"A","en":"Pernio-like COVID toes","ar":"آفات شبيهة بالشرث «أصابع كوفيد»"},{"letter":"B","en":"Koplik spots","ar":"بقع كوبليك"},{"letter":"C","en":"Condyloma acuminata","ar":"الثآليل التناسلية"},{"letter":"D","en":"Herpetic gingivostomatitis","ar":"التهاب الفم واللثة الهربسي"}],"correct":"A","explanation":{"en":"Acral chilblain-like lesions have been reported in association with COVID-19, often in younger patients with mild disease.","ar":"سُجلت آفات طرفية شبيهة بالشرث مع كوفيد وغالبًا لدى الأصغر سنًا ومرض خفيف."},"reasoning":{"en":"The acral location and violaceous edematous morphology identify the pattern.","ar":"يحدد المكان الطرفي والشكل البنفسجي المتورم النمط."},"image":null},{"id":"Q099","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"Case","difficulty":"Hard","source":"PDF p. 167","question":{"en":"A critically ill patient with COVID-19 develops retiform purpura and cool mottled limbs. What is the main concern?","ar":"مريض كوفيد بحالة حرجة ظهرت لديه فرفرية شبكية وأطراف باردة مبقعة. ما القلق الرئيسي؟"},"options":[{"letter":"A","en":"Thrombotic or occlusive vasculopathy","ar":"اعتلال وعائي تخثري أو انسدادي"},{"letter":"B","en":"Benign common warts","ar":"ثآليل شائعة حميدة"},{"letter":"C","en":"Simple molluscum","ar":"مليساء بسيطة"},{"letter":"D","en":"Uncomplicated rubella","ar":"حصبة ألمانية غير معقدة"}],"correct":"A","explanation":{"en":"Retiform purpura in severe COVID-19 can reflect vascular occlusion and systemic coagulopathy.","ar":"قد تعكس الفرفرية الشبكية في كوفيد الشديد انسدادًا وعائيًا واضطراب تخثر جهازيًا."},"reasoning":{"en":"This morphology requires urgent systemic evaluation rather than reassurance about an isolated rash.","ar":"يحتاج هذا الشكل تقييمًا جهازيًا عاجلًا بدل الطمأنة بشأن طفح منفرد."},"image":null},{"id":"Q100","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"Case","difficulty":"Hard","source":"PDF p. 166","question":{"en":"A patient develops a diffuse itchy morbilliform eruption after COVID-19 and several new medications. What is the safest interpretation?","ar":"مريض ظهر لديه طفح منتشر حاك شبيه بالحصبة بعد كوفيد وعدة أدوية جديدة. ما التفسير الأكثر أمانًا؟"},"options":[{"letter":"A","en":"Consider both viral exanthem and drug eruption; review timing and red flags","ar":"النظر في طفح فيروسي وطفح دوائي مع مراجعة التوقيت وعلامات الخطر"},{"letter":"B","en":"Assume COVID is always the only cause","ar":"اعتبار كوفيد السبب الوحيد دائمًا"},{"letter":"C","en":"Ignore mucosal involvement or systemic signs","ar":"تجاهل إصابة الأغشية والعلامات الجهازية"},{"letter":"D","en":"Diagnose HPV","ar":"تشخيص HPV"}],"correct":"A","explanation":{"en":"Morbilliform eruptions are nonspecific and may result from infection or medication exposure.","ar":"الطفوح الشبيهة بالحصبة غير نوعية وقد تنتج عن العدوى أو الأدوية."},"reasoning":{"en":"A timeline, medication review, mucosal examination, and systemic red-flag assessment prevent missing a severe drug reaction.","ar":"يمنع تسلسل زمني ومراجعة الأدوية وفحص الأغشية وعلامات الخطر تفويت تفاعل دوائي شديد."},"image":null}]);
